```ts
import { Effect, Data } from "effect";

interface Cart { readonly id: string; readonly totalCents: number }
interface Reservation { readonly reservationId: string }
interface Charge { readonly chargeId: string }
interface Receipt { readonly receiptId: string }

class InventoryError extends Data.TaggedError("InventoryError")<{ readonly cartId: string }> {}
class PaymentError extends Data.TaggedError("PaymentError")<{ readonly chargeAttempt: string }> {}
class ReceiptError extends Data.TaggedError("ReceiptError")<{ readonly cartId: string }> {}

declare const reserve: (c: Cart) => Effect.Effect<Reservation, InventoryError>;
declare const charge: (c: Cart, r: Reservation) => Effect.Effect<Charge, PaymentError>;
declare const emit: (c: Cart, ch: Charge) => Effect.Effect<Receipt, ReceiptError>;

export const checkout = (
  cart: Cart
): Effect.Effect<Receipt, InventoryError | PaymentError | ReceiptError> =>
  Effect.gen(function* () {
    const reservation = yield* reserve(cart);
    const chargeRes = yield* charge(cart, reservation);
    const receipt = yield* emit(cart, chargeRes);
    return receipt;
  });
```

The full error union stays in the outer `Effect` type, so callers get exhaustive `catchTag` coverage at compile time.

```ts
import { Effect } from "effect";

// v2 required an adapter argument so yield* could lift a plain Effect.
// v3 drops the adapter entirely — the generator takes zero args and
// yield* consumes an Effect<A, E, R> directly, binding A.
export const one: Effect.Effect<number> = Effect.gen(function* () {
  return yield* Effect.succeed(1);
});

// Equivalent chained form for reference:
export const oneAgain: Effect.Effect<number> = Effect.gen(function* () {
  const n = yield* Effect.succeed(1);
  return n;
});
```

Dropping the adapter makes the generator body read as ordinary TS — every `yield*` is just "await this effect".

Every `yield* eff` where `eff: Effect<A, E, R>` contributes its `E` to the outer effect's error channel as a union. As long as you never catch, the outer type accumulates all failure modes, and the compiler forces exhaustive handling when you do catch.

```ts
import { Effect, Data } from "effect";

interface Event { readonly type: string; readonly payload: string }

class ParseError extends Data.TaggedError("ParseError")<{ readonly raw: string }> {}
class ValidationError extends Data.TaggedError("ValidationError")<{ readonly field: string }> {}

const parseJson = (raw: string): Effect.Effect<unknown, ParseError> =>
  Effect.try({ try: () => JSON.parse(raw) as unknown, catch: () => new ParseError({ raw }) });

const validate = (u: unknown): Effect.Effect<Event, ValidationError> => {
  if (typeof u === "object" && u !== null && "type" in u && "payload" in u) {
    const o = u as { type: unknown; payload: unknown };
    if (typeof o.type === "string" && typeof o.payload === "string") {
      return Effect.succeed({ type: o.type, payload: o.payload });
    }
  }
  return Effect.fail(new ValidationError({ field: "root" }));
};

export const parseEvent = (raw: string): Effect.Effect<Event, ParseError | ValidationError> =>
  Effect.gen(function* () {
    const parsed = yield* parseJson(raw);
    const event = yield* validate(parsed);
    return event;
  });
```

```ts
import { Effect, Data, Either } from "effect";

class Op1Error extends Data.TaggedError("Op1Error")<{ readonly reason: string }> {}
class Op2Error extends Data.TaggedError("Op2Error")<{ readonly reason: string }> {}

declare const op1: () => Effect.Effect<number, Op1Error>;
declare const op2: (n: number) => Effect.Effect<string, Op2Error>;

type OpError = Op1Error | Op2Error;

export const runBoth = (): Effect.Effect<
  { results: ReadonlyArray<number | string>; errors: ReadonlyArray<OpError> }
> =>
  Effect.gen(function* () {
    const a = yield* Effect.either(op1());
    const b = yield* Effect.either(op2(Either.isRight(a) ? a.right : 0));
    const results: Array<number | string> = [];
    const errors: OpError[] = [];
    if (Either.isRight(a)) results.push(a.right); else errors.push(a.left);
    if (Either.isRight(b)) results.push(b.right); else errors.push(b.left);
    return { results, errors };
  });
```

`Effect.either` converts a failure into a `Left`, letting the generator see both outcomes without short-circuiting on the first error.

