import { Effect, Context, Layer } from "effect";

interface Config { readonly host: string }
interface Service { readonly describe: () => Effect.Effect<string> }

const Config = Context.GenericTag<Config>("app/Config");
const Service = Context.GenericTag<Service>("app/Service");

const ConfigLive = Layer.succeed(Config, { host: "localhost" });
const ServiceLive = Layer.effect(
  Service,
  Effect.gen(function* () {
    const cfg = yield* Config;
    return { describe: () => Effect.succeed(`svc@${cfg.host}`) };
  })
);

// Layer.provide hides Config. Layer.provideMerge keeps it exposed.
const AppLayer = Layer.provideMerge(ServiceLive, ConfigLive);

const program = Effect.gen(function* () {
  const svc = yield* Service;
  const cfg = yield* Config; // still available
  const name = yield* svc.describe();
  return `${name} (${cfg.host})`;
});

export const runnable = Effect.provide(program, AppLayer);
```

`Layer.provideMerge(inner, deps)` satisfies `inner`'s dependencies AND re-exports `deps`' outputs in the resulting layer.

`Layer.merge(a, b)` is parallel composition: both `a` and `b` must produce their outputs, their requirements union, and their outputs union. Neither feeds the other.

`Layer.provide(inner, deps)` is vertical composition: `deps`' outputs satisfy `inner`'s requirements. `deps`' outputs are consumed, not re-exported.

```ts
import { Effect, Context, Layer } from "effect";

interface Clock { readonly now: () => Effect.Effect<number> }
interface Logger { readonly info: (msg: string) => Effect.Effect<void> }
interface Audit { readonly write: (msg: string) => Effect.Effect<void> }

const Clock = Context.GenericTag<Clock>("app/Clock");
const Logger = Context.GenericTag<Logger>("app/Logger");
const Audit = Context.GenericTag<Audit>("app/Audit");

const ClockLive = Layer.succeed(Clock, { now: () => Effect.succeed(Date.now()) });
const LoggerLive = Layer.succeed(Logger, { info: (m) => Effect.sync(() => console.log(m)) });

// Audit needs Clock AND Logger.
const AuditLive = Layer.effect(
  Audit,
  Effect.gen(function* () {
    const clock = yield* Clock;
    const log = yield* Logger;
    return {
      write: (msg: string) =>
        Effect.gen(function* () {
          const t = yield* clock.now();
          yield* log.info(`${t} ${msg}`);
        }),
    };
  })
);

// Merge independent leaves, then provide them to Audit.
const Deps = Layer.merge(ClockLive, LoggerLive);
export const AppLayer = Layer.provide(AuditLive, Deps);
```
